  font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont,
    'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  min-height: 100vh;
}

main {
  max-width: 720px;
  margin: 0 auto;
  padding: 3rem 1.5rem;
}

h1 {
  font-size: 2rem;
  margin-bottom: 0.5rem;
}

p.lead {
  color: #a9b3d6;
  margin-top: 0;
}

form {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  background: var(--muted);
  padding: 1.5rem;
  border-radius: 12px;
  margin-top: 1.5rem;
}

input[type='file'] {
  padding: 0.5rem;
  background: rgba(255, 255, 255, 0.05);
  color: var(--fg);
  border-radius: 8px;
  border: 1px dashed rgba(255, 255, 255, 0.2);
}

button {
  background: var(--accent);
  color: white;
  border: none;
  padding: 0.75rem 1.25rem;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
}

button:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.preview {
  margin-top: 1.5rem;
  padding: 1rem;
  border-radius: 12px;
  background: var(--muted);
}

.preview img {
  max-width: 100%;
  border-radius: 8px;
  display: block;
}

.error {
  color: #ff6b6b;
  margin-top: 0.5rem;
}

.meta {
  font-size: 0.875rem;
  color: #a9b3d6;
  margin-top: 0.5rem;
}

a {
  color: var(--accent);
}

